// Input: { text: '...', source_lang: 'it', target_langs?: [...], style?: 'reddit|press|tweet|landing' }
const body = $input.first().json.body || $input.first().json;
const text = body.text || '';
const source = body.source_lang || 'it';
const defaults = ['en','de','fr','es','pt','ru','ja','ko','zh','ar','hi','tr','id','pl'];
const targets = Array.isArray(body.target_langs) && body.target_langs.length ? body.target_langs : defaults;
const style = body.style || 'generic';
if (!text || text.length < 5) {
  return [{ json: { error: 'text required (min 5 chars)' }}];
}
return targets.map(lang => ({ json: { text, source, target: lang, style }}));

