const items = $input.all();
const out = {};
for (const it of items) {
  const ctx = $('Parse request').itemMatching(items.indexOf(it))?.json || it.json;
  const llm = it.json;
  const text = (llm.response || llm.message?.content || '').trim();
  out[ctx.target || 'unknown'] = text;
}
return [{ json: { translations: out, count: Object.keys(out).length }}];
